const config = $input.first().json;

const videos = [
  config.video1Url,
  config.video2Url,
  config.video3Url
].filter(url => url && (url.includes('youtube.com') || url.includes('youtu.be')));

if (videos.length === 0) {
  throw new Error('No valid YouTube URLs found. Please submit at least one YouTube URL.');
}

const extractVideoId = (url) => {
  try {
    if (url.includes('youtu.be/')) {
      return url.split('youtu.be/')[1].split('?')[0].split('&')[0];
    }
    const urlObj = new URL(url);
    return urlObj.searchParams.get('v') || '';
  } catch (e) {
    return '';
  }
};

return videos.map((url, index) => {
  const videoId = extractVideoId(url);
  return {
    json: {
      originalUrl: url,
      videoId,
      videoIndex: index + 1,
      totalVideos: videos.length,
      isLastVideo: index === videos.length - 1,
      youtubeApiKey: config.youtubeApiKey,
      wayinVideoApiKey: config.wayinVideoApiKey,
      sheetId: config.sheetId,
      sheetName: config.sheetName,
      recipientEmail: config.recipientEmail,
      senderName: config.senderName,
      yourNiche: config.yourNiche,
      submittedBy: config.submittedBy,
      today: config.today
    }
  };
});

const response = $input.first().json;
const videoData = $('3. Code — Extract Video IDs').item.json;

const item = response?.items?.[0];

if (!item) {
  throw new Error('Video not found or is private: ' + videoData.originalUrl);
}

const snippet = item.snippet || {};
const stats = item.statistics || {};
const details = item.contentDetails || {};

const rawDuration = details.duration || 'PT0S';
const durationMatch = rawDuration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
const hours = parseInt(durationMatch?.[1] || 0);
const minutes = parseInt(durationMatch?.[2] || 0);
const seconds = parseInt(durationMatch?.[3] || 0);
const duration = (hours > 0 ? hours + 'h ' : '') + (minutes > 0 ? minutes + 'm ' : '') + seconds + 's';

const views = parseInt(stats.viewCount || 0).toLocaleString('en-US');

const publishedDate = snippet.publishedAt
  ? new Date(snippet.publishedAt).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : 'Unknown';

return [{
  json: {
    videoId: videoData.videoId,
    originalUrl: videoData.originalUrl,
    title: snippet.title || 'Unknown Title',
    channel: snippet.channelTitle || 'Unknown Channel',
    description: (snippet.description || '').substring(0, 500),
    views,
    duration,
    publishedDate,
    videoIndex: videoData.videoIndex,
    totalVideos: videoData.totalVideos,
    isLastVideo: videoData.isLastVideo,
    wayinVideoApiKey: videoData.wayinVideoApiKey,
    sheetId: videoData.sheetId,
    sheetName: videoData.sheetName,
    recipientEmail: videoData.recipientEmail,
    senderName: videoData.senderName,
    yourNiche: videoData.yourNiche,
    submittedBy: videoData.submittedBy,
    today: videoData.today
  }
}];

const response = $input.first().json;
const videoData = $('5. Code — Process Video Metadata').item.json;

const transcriptId = response?.data?.id;

if (!transcriptId) {
  throw new Error('WayinVideo did not return a task ID. Check your WayinVideo API key.');
}

return [{
  json: {
    transcriptId,
    transcriptStatus: response?.data?.status || 'CREATED',
    pollCount: 0,
    videoId: videoData.videoId,
    originalUrl: videoData.originalUrl,
    title: videoData.title,
    channel: videoData.channel,
    description: videoData.description,
    views: videoData.views,
    duration: videoData.duration,
    publishedDate: videoData.publishedDate,
    videoIndex: videoData.videoIndex,
    totalVideos: videoData.totalVideos,
    isLastVideo: videoData.isLastVideo,
    wayinVideoApiKey: videoData.wayinVideoApiKey,
    sheetId: videoData.sheetId,
    sheetName: videoData.sheetName,
    recipientEmail: videoData.recipientEmail,
    senderName: videoData.senderName,
    yourNiche: videoData.yourNiche,
    submittedBy: videoData.submittedBy,
    today: videoData.today
  }
}];

const pollResponse = $input.first().json;
const prev = $('7. Code — Save Transcript Task ID').item.json;

const status = pollResponse?.data?.status || 'UNKNOWN';
const pollCount = (prev.pollCount || 0) + 1;

if (pollCount >= 15 && status !== 'SUCCEEDED') {
  throw new Error('WayinVideo transcription timed out after 15 polls (about 11 minutes). Task ID: ' + prev.transcriptId);
}

if (status === 'FAILED') {
  const errorMsg = pollResponse?.data?.error_message || 'Unknown error';
  throw new Error('WayinVideo transcription failed: ' + errorMsg);
}

let transcriptText = '';
if (status === 'SUCCEEDED') {
  const segments = pollResponse?.data?.transcript || [];
  let currentSpeaker = '';
  segments.forEach(seg => {
    const speaker = seg.speaker || 'Speaker';
    const text = (seg.text || '').trim();
    if (!text) return;
    if (speaker !== currentSpeaker) {
      transcriptText += '\n' + speaker + ': ';
      currentSpeaker = speaker;
    }
    transcriptText += text + ' ';
  });
  transcriptText = transcriptText.trim();
}

if (!transcriptText || transcriptText.length < 50) {
  transcriptText = 'Transcript not available. Using video description instead:\n\n' + (prev.description || 'No description available.');
}

transcriptText = transcriptText.substring(0, 5000);

return [{
  json: {
    transcriptId: prev.transcriptId,
    transcriptStatus: status,
    transcriptText,
    pollCount,
    isReady: status === 'SUCCEEDED',
    videoId: prev.videoId,
    originalUrl: prev.originalUrl,
    title: prev.title,
    channel: prev.channel,
    views: prev.views,
    duration: prev.duration,
    publishedDate: prev.publishedDate,
    videoIndex: prev.videoIndex,
    totalVideos: prev.totalVideos,
    isLastVideo: prev.isLastVideo,
    wayinVideoApiKey: prev.wayinVideoApiKey,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    recipientEmail: prev.recipientEmail,
    senderName: prev.senderName,
    yourNiche: prev.yourNiche,
    submittedBy: prev.submittedBy,
    today: prev.today
  }
}];

