{
  "type": "object",
  "properties": {
    "summary": { "type": "string", "description": "3 to 4 sentence video summary" },
    "keyTopics": { "type": "array", "items": { "type": "string" }, "description": "5 key topics covered" },
    "bestQuote": { "type": "string", "description": "Most memorable statement from video" },
    "targetAudience": { "type": "string", "description": "Who this video is for" },
    "relevanceScore": { "type": "number", "description": "Relevance from 1 to 10" },
    "contentGap": { "type": "string", "description": "What the video did not cover" }
  },
  "required": ["summary", "keyTopics", "bestQuote", "targetAudience", "relevanceScore", "contentGap"]
}

