const aiOutput = $input.first().json.output;
const videoData = $('10. Code — Check Transcript Status').item.json;

const score = aiOutput?.relevanceScore || 0;
const scoreLabel = score >= 8 ? 'High' : score >= 5 ? 'Medium' : 'Low';
const keyTopics = (aiOutput?.keyTopics || []).join(', ');

const loggedAt = new Date().toISOString().replace('T', ' ').substring(0, 16);

return [{
  json: {
    today: videoData.today,
    originalUrl: videoData.originalUrl,
    title: videoData.title,
    channel: videoData.channel,
    views: videoData.views,
    duration: videoData.duration,
    publishedDate: videoData.publishedDate,
    summary: aiOutput?.summary || 'Not available',
    keyTopics,
    bestQuote: aiOutput?.bestQuote || 'Not available',
    targetAudience: aiOutput?.targetAudience || 'Not available',
    relevanceScore: score + ' out of 10 — ' + scoreLabel,
    contentGap: aiOutput?.contentGap || 'Not available',
    submittedBy: videoData.submittedBy,
    loggedAt,
    rawScore: score,
    isLastVideo: videoData.isLastVideo,
    sheetId: videoData.sheetId,
    sheetName: videoData.sheetName,
    recipientEmail: videoData.recipientEmail,
    senderName: videoData.senderName,
    yourNiche: videoData.yourNiche
  }
}];

const lastItem = $('16. Code — Prepare Results').item.json;

let allItems = [];
try {
  allItems = $('16. Code — Prepare Results').all().map(i => i.json);
} catch (e) {
  allItems = [lastItem];
}

const today = lastItem.today;
const senderName = lastItem.senderName;
const recipientEmail = lastItem.recipientEmail;

const sorted = [...allItems].sort((a, b) => (b.rawScore || 0) - (a.rawScore || 0));

let body = 'Hello ' + senderName + ',\n\n';
body += 'Here is your YouTube Video Intelligence Report for ' + today + '.\n\n';
body += 'Total videos analyzed: ' + sorted.length + '\n\n';
body += '============================================================\n\n';

sorted.forEach((v, i) => {
  body +=
    (i + 1) + '. ' + (v.title || 'Unknown') + '\n' +
    'Channel: ' + (v.channel || 'Unknown') + '\n' +
    'Views: ' + (v.views || 'Unknown') + ' | Duration: ' + (v.duration || 'Unknown') + ' | Published: ' + (v.publishedDate || 'Unknown') + '\n' +
    'URL: ' + (v.originalUrl || 'Unknown') + '\n' +
    'Relevance score: ' + (v.relevanceScore || 'Unknown') + '\n\n' +
    'Summary:\n' + (v.summary || 'Not available') + '\n\n' +
    'Key topics: ' + (v.keyTopics || 'Not available') + '\n\n' +
    'Best quote: ' + (v.bestQuote || 'Not available') + '\n\n' +
    'Best for: ' + (v.targetAudience || 'Not available') + '\n\n' +
    'Content gap to exploit: ' + (v.contentGap || 'Not available') + '\n\n' +
    '------------------------------------------------------------\n\n';
});

body += 'All video analyses are saved in your Google Sheets YouTube Intelligence tab.\n\n';
body += 'Best regards,\n' + senderName;

return [{
  json: {
    emailSubject: 'YouTube Video Intelligence Report — ' + sorted.length + ' videos — ' + today,
    emailBody: body,
    recipientEmail
  }
}];
